/** Backlog candidates are never public; this contract is asserted in QA. */
export const BACKLOG_IS_PUBLIC = false as const;

export const BEHAVIOR_BACKLOG_COUNT = BEHAVIOR_BACKLOG.length;

export function backlogByStatus(status: BacklogStatus): BehaviorBacklogItem[] {
  return BEHAVIOR_BACKLOG.filter((b) => b.status === status);
}
